    group('10 — Episodic capture, redaction, and settings toggles'); const ch10=await createChat(A,'agent','episodic and governance'); const epiTok=tok('episodicalpha'); const er=await send(A,ch10,`Episodic marker ${epiTok}: please reply briefly.`); await check('episodic marker turn returns 200',()=>er.ok&&notMisrouted(er.reply),()=>compact(er.reply||er.body)); const epiRows=await poll('episodic user marker capture',()=>getAdminBucket('episodic',A!.userId,1000),rows=>JSON.stringify(rows).includes(epiTok)); await check('episodic user row captured with alphabetic sentinel',()=>!!epiRows&&JSON.stringify(epiRows).includes(epiTok),()=>`after=${epiRows?.length??'null'}`,{id:'episodic-extraction',benchmark:'LongMemEval / LoCoMo',capability:'information extraction',weight:1}); const piiTok=tok('piimarker'); const pii=await send(A,ch10,`Governance marker ${piiTok}. SSN 123-45-6789. Card 4111111111111111. api_key=sk-proj-TESTKEYABCDEFGHIJKLMN. Preserve harmless context phrase SUNNYORCHARD.`); await check('PII-containing turn does not crash',()=>pii.ok,()=>compact(pii.reply||pii.body)); const piiRows=await poll('PII episodic redaction',()=>getAdminBucket('episodic',A!.userId,1000),rows=>JSON.stringify(rows).includes(piiTok)); const piiText=JSON.stringify(piiRows??[]); await check('raw PII absent from episodic memory',()=>!!piiRows&&!includesAny(piiText,['123-45-6789','4111111111111111','TESTKEYABCDEFGHIJKLMN']),()=>compact(piiText),{id:'governance-redaction-coverage',benchmark:'Operational safety',capability:'redaction coverage',weight:1.5}); await check('non-sensitive context survives redaction',()=>!!piiRows&&piiText.includes('SUNNYORCHARD')&&piiText.includes('[REDACTED]'),()=>compact(piiText),{id:'governance-context-preservation',benchmark:'Operational safety',capability:'context-preserving redaction',weight:1}); const setOff=await putSettings({enable_episodic:false}); await check('disable episodic accepted',()=>setOff.status===200,()=>compact(setOff.body)); const offTok=to