    group('11 — Max cap, trim behaviour, then restore before concurrency'); const originalCap=Number(settingsSnapshot?.max_episodic_per_user??200); await putSettings({max_episodic_per_user:6,enable_episodic:true}); const ch11=await createChat(C,'agent','cap trim'); for(let i=0;i<5;i++)await send(C,ch11,`Trim marker ${tok(`trim${String.fromCharCode(65+i)}`)} brief reply.`); await sleep(4000); const capRows=await getAdminBucket('episodic',C.userId,1000); await check('episodic rows are trimmed to configured cap',()=>capRows.length<=6&&capRows.length>0,()=>`count=${capRows.length}; cap=6`,{id:'memory-cap-trimming',benchmark:'Operational safety',capability:'capacity management',weight:.8}); await putSettings({max_episodic_per_user:originalCap}); const restored=await getSettings(); await check('episodic cap restored before concurrency',()=>Number(restored?.max_episodic_per_user)===originalCap,()=>compact(restored));

